import React, { useState, useEffect } from 'react';
import api from '../services/api';
import { toast } from 'react-toastify';

const AuditLogs = () => {
  const [logs, setLogs] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchLogs();
  }, []);

  const fetchLogs = async () => {
    try {
      setLoading(true);
      const res = await api.get('/admin/audit-logs');
      // Handle wrapped response
      const logsData = res.data?.data || res.data || [];
      setLogs(Array.isArray(logsData) ? logsData : []);
    } catch (err) {
      console.error(err);
      toast.error('Failed to fetch audit logs');
    } finally {
      setLoading(false);
    }
  };

  const getActionIcon = (action) => {
    if (action.toLowerCase().includes('approved')) return '✅';
    if (action.toLowerCase().includes('rejected')) return '❌';
    if (action.toLowerCase().includes('created')) return '➕';
    if (action.toLowerCase().includes('updated')) return '📝';
    if (action.toLowerCase().includes('deleted')) return '🗑️';
    return '📋';
  };

  return (
    <div className="fade-in">
      <div className="flex-between mb-6">
        <div>
          <h2 className="page-title" style={{ marginBottom: '0.5rem' }}>📜 Audit Logs</h2>
          <p style={{ color: 'var(--text-secondary)', fontSize: '0.875rem', margin: 0 }}>
            Track all system activities and changes
          </p>
        </div>
        <div style={{
          display: 'flex',
          alignItems: 'center',
          gap: '1rem',
          padding: '0.75rem 1.25rem',
          background: 'var(--bg-card)',
          borderRadius: '0.75rem',
          border: '1px solid var(--border-bright)'
        }}>
          <span style={{ fontSize: '1.25rem' }}>📋</span>
          <div>
            <div style={{ fontSize: '0.75rem', color: 'var(--text-secondary)' }}>Total Logs</div>
            <div style={{ fontSize: '1.25rem', fontWeight: 700, color: 'var(--text-primary)' }}>
              {logs.length}
            </div>
          </div>
        </div>
      </div>

      <div className="card" style={{ padding: '1.5rem' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
          <h4 style={{ margin: 0, color: 'var(--text-primary)', fontSize: '1.125rem', fontWeight: 600 }}>
            🕐 Activity Timeline
          </h4>
          <button
            onClick={fetchLogs}
            className="btn btn-primary"
            style={{ padding: '0.5rem 1rem', fontSize: '0.875rem', display: 'flex', alignItems: 'center', gap: '0.5rem' }}
          >
            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
              <path d="M21.5 2v6h-6M2.5 22v-6h6M2 11.5a10 10 0 0 1 18.8-4.3M22 12.5a10 10 0 0 1-18.8 4.2" />
            </svg>
            Refresh
          </button>
        </div>

        {loading ? (
          <div className="loading-container" style={{ minHeight: '300px' }}>
            <div className="loading-spinner"></div>
            <div style={{ color: 'var(--text-secondary)', marginTop: '1rem' }}>Loading audit logs...</div>
          </div>
        ) : logs.length === 0 ? (
          <div style={{ textAlign: 'center', padding: '3rem', color: 'var(--text-secondary)' }}>
            <div style={{ fontSize: '3rem', marginBottom: '1rem' }}>📭</div>
            <div style={{ fontSize: '1.125rem', fontWeight: 500, color: 'var(--text-primary)' }}>No audit logs yet</div>
            <div style={{ marginTop: '0.5rem' }}>System activities will appear here</div>
          </div>
        ) : (
          <div style={{ display: 'flex', flexDirection: 'column', gap: '0.75rem' }}>
            {logs.map((log, idx) => (
              <div
                key={log._id || idx}
                className="activity-item"
                style={{
                  display: 'flex',
                  alignItems: 'flex-start',
                  padding: '1rem',
                  background: 'var(--bg-hover)',
                  borderRadius: '0.75rem',
                  border: '1px solid var(--border)',
                  transition: 'all 0.3s ease'
                }}
              >
                <div style={{
                  width: '40px',
                  height: '40px',
                  borderRadius: '50%',
                  background: 'var(--gradient-primary)',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  marginRight: '1rem',
                  flexShrink: 0,
                  fontSize: '1.25rem'
                }}>
                  {getActionIcon(log.action)}
                </div>
                <div style={{ flex: 1 }}>
                  <div style={{
                    fontWeight: '500',
                    color: 'var(--text-primary)',
                    marginBottom: '0.25rem',
                    fontSize: '0.9375rem'
                  }}>
                    {log.action}
                  </div>
                  <div style={{
                    fontSize: '0.75rem',
                    color: 'var(--text-secondary)',
                    display: 'flex',
                    alignItems: 'center',
                    gap: '0.5rem',
                    flexWrap: 'wrap'
                  }}>
                    <span>
                      👤 {log.performedBy?.fullName || 'System'}
                    </span>
                    <span>•</span>
                    <span>
                      🕐 {new Date(log.timestamp).toLocaleString()}
                    </span>
                    {log.targetEntity && (
                      <>
                        <span>•</span>
                        <span title={log.targetEntity}>
                          🎯 {log.targetEntity.split(':')[0]}
                        </span>
                      </>
                    )}
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
export default AuditLogs;
